{
  "formal_minutes": {
    "decisions": [
      {
        "item": "공개 릴리스 목표는 스모크 테스트 통과를 조건으로 금요일 15:00 KST로 한다.",
        "certainty": "confirmed"
      },
      {
        "item": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다. 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다.",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": {
      "rejected_proposals": [
        {
          "item": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경하자는 제안",
          "status": "rejected"
        }
      ],
      "internal_stretch_goals": [
        {
          "item": "수요일 릴리스",
          "status": "internal_stretch_goal_only"
        }
      ],
      "unassigned_or_unconfirmed_items": [
        {
          "item": "README 설치 단계는 가능하면 목요일까지 검토되어야 한다는 의견",
          "status": "owner_not_assigned"
        }
      ]
    },
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "suggested_unassigned",
      "source_certainty": "explicit_but_not_confirmed_as_owned_action"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
